      <header className="flex flex-col gap-2 border-b border-white/10 pb-6 sm:flex-row sm:items-end sm:justify-between">
        <div>
          <h2 className="text-2xl font-semibold text-chalk">Knockout path</h2>
          <p className="mt-1 text-sm text-white/60">
            Annex C combination{" "}
            <span className="font-mono text-gold">#{snap.combinationId}</span> —{" "}
            advancing third groups:{" "}
            <span className="font-mono text-white/80">
              {snap.advancingThirdGroups.sort().join(" ")}
            </span>
          </p>
        </div>
      </header>
      {ROUND_ORDER.map((round) => {
        const matches = KNOCKOUT_MATCHES.filter((m) => m.round === round);
        if (matches.length === 0) return null;
        return (
          <div key={round}>
            <h3 className="mb-3 text-xs font-bold uppercase tracking-[0.2em] text-gold/90">
              {round === "R32"
                ? "Round of 32"
                : round === "R16"
                  ? "Round of 16"
                  : round === "QF"
                    ? "Quarter-finals"
                    : round === "SF"
                      ? "Semi-finals"
                      : round === "TP"
                        ? "Third place"
                        : "Final"}
            </h3>
            <div className="flex gap-3 overflow-x-auto pb-2">
              {matches.map((m) => {
                const { home, away } = resolveMatchSides(m.id, snap, koWinners);
                const ready = canPickWinner(m.id, snap, koWinners);
                const picked = koWinners[m.id];
                return (
                  <div
                    key={m.id}
                    className="min-w-[220px] shrink-0 rounded-2xl border border-white/10 bg-pitch-900/90 p-4 shadow-md shadow-black/40"
                  >
                    <div className="mb-2 flex items-center justify-between gap-2">
                      <span className="font-mono text-[10px] text-white/40">
                        M{m.id}
                      </span>
                      <span className="truncate text-[10px] text-white/45">
                        {m.label}
                      </span>
                    </div>
                    <button
                      type="button"
                      disabled={!ready || !home}
                      onClick={() => ready && home && setKoWinner(m.id, "home")}
                      className={`mb-2 w-full rounded-xl border px-2 py-2 text-left text-sm transition ${
                        picked === "home"
                          ? "border-gold bg-gold/15 text-chalk"
                          : "border-white/10 bg-black/25 text-white/85 hover:border-white/25"
                      } disabled:cursor-not-allowed disabled:opacity-40`}
                    >
                      {home ?? "—"}
                    </button>
                    <button
                      type="button"
                      disabled={!ready || !away}
                      onClick={() => ready && away && setKoWinner(m.id, "away")}
                      className={`w-full rounded-xl border px-2 py-2 text-left text-sm transition ${
                        picked === "away"
                          ? "border-gold bg-gold/15 text-chalk"
                          : "border-white/10 bg-black/25 text-white/85 hover:border-white/25"
                      } disabled:cursor-not-allowed disabled:opacity-40`}
                    >
                      {away ?? "—"}
                    </button>
                  </div>
                );
              })}
            </div>
          </div>
        );
      })}
    </section>
  );
}

import SimulatorClient from "@/components/SimulatorClient";

export default function Home() {
  return <SimulatorClient />;
}

import { describe, expect, it } from "vitest";
import { sortGroupStandings, matchKey, createEmptyScores } from "./standings";
import { getGroupTeamNames } from "./thirdPlaceSelection";
import { resolveAnnexThirdMapping } from "./annexC";
import type { GroupLetter } from "./types";
import {
  buildQualifierSnapshot,
  KNOCKOUT_MATCHES,
  resolveMatchSides,
} from "./knockoutBracket";

function allWins(
  group: GroupLetter,
  winnerIdx: number,
  names: string[],
): Record<string, [number, number] | null> {
  const scores = createEmptyScores();
  const n = names.length;
  for (let mi = 0; mi < 6; mi++) {
    const key = matchKey(group, mi);
    const [a, b] = [
      [0, 1],
      [2, 3],
      [0, 2],
      [1, 3],
      [0, 3],
      [1, 2],
    ][mi]!;
    let home = 1;
    let away = 0;
    if (a === winnerIdx) {
      home = 2;
      away = 0;
    } else if (b === winnerIdx) {
      home = 0;
      away = 2;
    }
    scores[key] = [home, away];
  }
  return scores;
}

describe("sortGroupStandings", () => {
  it("orders by points and goal difference", () => {
    const names = ["A", "B", "C", "D"];
    const scores: Record<string, [number, number] | null> = {};
    const g = "A" as GroupLetter;
    scores[matchKey(g, 0)] = [3, 0];
    scores[matchKey(g, 1)] = [0, 0];
    scores[matchKey(g, 2)] = [3, 0];
    scores[matchKey(g, 3)] = [0, 0];
    scores[matchKey(g, 4)] = [3, 0];
    scores[matchKey(g, 5)] = [0, 0];
    const t = sortGroupStandings(g, names, scores);
    expect(t[0].name).toBe("A");
    expect(t[0].points).toBe(9);
  });
});

describe("Annex C", () => {
  it("resolves combination 1 (EFGHIJKL)", () => {
    const adv: GroupLetter[] = ["E", "F", "G", "H", "I", "J", "K", "L"];
    const r = resolveAnnexThirdMapping(adv);
    expect(r.combinationId).toBe(1);
    expect(r.thirdVsWinner.A).toBe("E");
    expect(r.thirdVsWinner.L).toBe("K");
  });

  it("resolves combination 495 (ABCDEFGH)", () => {
    const adv: GroupLetter[] = ["A", "B", "C", "D", "E", "F", "G", "H"];
    const r = resolveAnnexThirdMapping(adv);
    expect(r.combinationId).toBe(495);
    expect(r.thirdVsWinner.A).toBe("H");
    expect(r.thirdVsWinner.E).toBe("F");
  });

  it("resolves row 82 from Wikipedia table", () => {
    const adv: GroupLetter[] = ["B", "C", "G", "H", "I", "J", "K", "L"];
    const r = resolveAnnexThirdMapping(adv);
    expect(r.combinationId).toBe(82);
  });
});

describe("knockout wiring", () => {
  it("has 32 knockout matches ending at the final", () => {
    expect(KNOCKOUT_MATCHES.length).toBe(32);
    expect(KNOCKOUT_MATCHES.at(-1)?.id).toBe(104);
  });

  it("builds a snapshot when all scores filled with identical draws", () => {
    const scores = createEmptyScores();
    const letters: GroupLetter[] = [
      "A",
      "B",
      "C",
      "D",
      "E",
      "F",
      "G",
      "H",
      "I",
      "J",
      "K",
      "L",
    ];
    for (const g of letters) {
      for (let i = 0; i < 6; i++) {
        scores[matchKey(g, i)] = [1, 1];
      }
    }
    const snap = buildQualifierSnapshot(scores);
    expect(snap).not.toBeNull();
    if (!snap) return;
    expect(snap.advancingThirdGroups.length).toBe(8);
    const { home, away } = resolveMatchSides(73, snap, {});
    expect(home).toBeTruthy();
    expect(away).toBeTruthy();
  });
});

